// Simulate temperature sensor data
let temp = 20 + Math.random() * 10;
let humidity = 40 + Math.random() * 20;
let pressure = 1000 + Math.random() * 50;

// Prepare holding registers (addresses 0-9)
msg.payload = {
    'value': [
        Math.floor(temp * 10),      // Address 0: Temperature x10
        Math.floor(humidity * 10),   // Address 1: Humidity x10
        Math.floor(pressure),        // Address 2: Pressure
        Date.now() & 0xFFFF,         // Address 3: Timestamp low
        (Date.now() >> 16) & 0xFFFF, // Address 4: Timestamp high
        0x1234,                      // Address 5: Device ID
        0x0100,                      // Address 6: Firmware version
        Math.floor(Math.random() * 100), // Address 7: Random value
        0xABCD,                      // Address 8: Status flags
        0x5678                       // Address 9: Error code
    ],
    'register': 'holding',
    'address': 0,
    'disableMsgOutput': 0
};

return msg;

// Simulate digital outputs (coils)
let coils = [];
for (let i = 0; i < 16; i++) {
    coils.push(Math.random() > 0.5);
}

msg.payload = {
    'value': coils,
    'register': 'coils',
    'address': 0,
    'disableMsgOutput': 0
};

return msg;

// Parse and display connection status
if (msg.status) {
    let status = {
        text: msg.status.text || '',
        fill: msg.status.fill || 'grey',
        shape: msg.status.shape || 'ring',
        timestamp: new Date().toISOString()
    };

    // Check for TLS connection
    if (status.text.includes('connected')) {
        msg.payload = {
            status: 'TLS Client Connected',
            secure: true,
            details: status
        };
    } else {
        msg.payload = {
            status: status.text,
            secure: false,
            details: status
        };
    }

    return msg;
}

return null;
